<?php
session_start();
$config = require dirname(__DIR__) . '/config.php';
$error = '';
if (isset($_GET['logout'])) { session_destroy(); header('Location: ./'); exit; }
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['username'], $_POST['password'])) {
  if ($_POST['username'] === $config['admin']['username'] && $_POST['password'] === $config['admin']['password']) {
    $_SESSION['unistone_admin'] = true;
    header('Location: ./'); exit;
  }
  $error = 'Невірний логін або пароль';
}
$authorized = !empty($_SESSION['unistone_admin']);
?><!DOCTYPE html><html lang="uk"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Unistone CRM</title><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700;800&display=swap" rel="stylesheet"><style>:root{--bg:#0a1018;--panel:#101823;--panel2:#0d141d;--text:#eef4fb;--muted:#91a5bf;--blue:#1d6cf0;--gold:#cba15a;--green:#22c55e;--red:#ef4444;--line:rgba(255,255,255,.08);--glass:rgba(255,255,255,.05);--shadow:0 24px 60px rgba(0,0,0,.34)}*{box-sizing:border-box}body{margin:0;font-family:Montserrat,sans-serif;color:var(--text);background:radial-gradient(circle at top left,rgba(29,108,240,.14),transparent 26%),radial-gradient(circle at top right,rgba(203,161,90,.1),transparent 22%),linear-gradient(180deg,#091018,#0d141d 50%,#091018)}a{text-decoration:none;color:inherit}.wrap{min-height:100vh;padding:24px}.card{background:linear-gradient(165deg,rgba(255,255,255,.09),rgba(255,255,255,.04));border:1px solid var(--line);border-radius:24px;box-shadow:var(--shadow);backdrop-filter:blur(18px)}.login{max-width:460px;margin:8vh auto;padding:34px}.logo{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:18px;background:linear-gradient(180deg,rgba(8,13,21,.9),rgba(10,16,24,.76));border:1px solid rgba(255,255,255,.12);margin-bottom:18px}.logo img{height:42px}.title{font-size:30px;font-weight:800;margin:0 0 8px}.sub{color:var(--muted);font-size:14px;line-height:1.7;margin:0 0 22px}input,select,textarea{width:100%;padding:13px 14px;border-radius:14px;border:1px solid rgba(255,255,255,.08);background:rgba(255,255,255,.05);color:#fff;font:500 14px Montserrat,sans-serif;outline:none}input:focus,select:focus,textarea:focus{border-color:rgba(29,108,240,.8);box-shadow:0 0 0 4px rgba(29,108,240,.14)}.btn{display:inline-flex;align-items:center;justify-content:center;gap:8px;padding:13px 18px;border:none;border-radius:14px;background:linear-gradient(135deg,var(--blue),#1558c0);color:#fff;font:700 14px Montserrat,sans-serif;cursor:pointer;transition:.2s}.btn:hover{transform:translateY(-2px)}.err{margin-top:10px;color:#ffb4b4;font-size:13px}.top{display:flex;justify-content:space-between;align-items:center;gap:16px;margin-bottom:18px;position:sticky;top:0;padding:8px 0 16px;background:linear-gradient(180deg,#091018 55%,rgba(9,16,24,0))}.head-left{display:flex;align-items:center;gap:14px}.ghost{background:rgba(255,255,255,.05);border:1px solid var(--line)}.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:20px}.metric{padding:20px}.metric .n{font-size:30px;font-weight:800;margin-top:6px}.metric .l{font-size:12px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em}.table-card{padding:18px}.tools{display:flex;justify-content:space-between;gap:12px;flex-wrap:wrap;margin-bottom:16px}.tools-left,.tools-right{display:flex;gap:10px;flex-wrap:wrap}.filter{padding:10px 14px;border-radius:12px;background:rgba(255,255,255,.04);border:1px solid var(--line);color:#d0d9e6;cursor:pointer;font:700 12px Montserrat,sans-serif}.filter.active{background:rgba(29,108,240,.12);border-color:rgba(29,108,240,.55);color:#9fc2ff}table{width:100%;border-collapse:collapse}th,td{padding:13px 12px;text-align:left;border-bottom:1px solid rgba(255,255,255,.05);font-size:13px;vertical-align:top}th{font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:var(--muted)}tr:hover{background:rgba(255,255,255,.02)}.badge{display:inline-block;padding:5px 10px;border-radius:999px;font-size:11px;font-weight:700}.new{background:rgba(29,108,240,.12);color:#9fc2ff}.inwork{background:rgba(203,161,90,.12);color:#f1d59d}.done{background:rgba(34,197,94,.12);color:#8ff0b1}.rejected{background:rgba(239,68,68,.12);color:#ffb0b0}.row-actions{display:flex;gap:8px;flex-wrap:wrap}.mini{padding:8px 10px;border-radius:10px;background:rgba(255,255,255,.05);border:1px solid var(--line);color:#fff;font:700 11px Montserrat,sans-serif;cursor:pointer}.empty{padding:38px 10px;color:var(--muted);text-align:center}.modal{position:fixed;inset:0;background:rgba(0,0,0,.6);display:none;align-items:center;justify-content:center;padding:16px}.modal.open{display:flex}.modal-card{width:min(760px,100%);padding:22px}.modal-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.field{padding:12px 14px;border-radius:14px;background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.06)}.field b{display:block;font-size:11px;letter-spacing:.08em;color:var(--muted);text-transform:uppercase;margin-bottom:8px}.modal-actions{display:flex;gap:10px;justify-content:flex-end;margin-top:16px}@media(max-width:1024px){.grid{grid-template-columns:repeat(2,1fr)}th:nth-child(4),td:nth-child(4),th:nth-child(5),td:nth-child(5){display:none}}@media(max-width:767px){.wrap{padding:14px}.login{margin:3vh auto;padding:22px}.grid{grid-template-columns:1fr}.top{flex-direction:column;align-items:flex-start}.tools{flex-direction:column}.modal-grid{grid-template-columns:1fr}table,thead,tbody,th,td,tr{display:block}thead{display:none}tr{padding:12px 0;border-bottom:1px solid rgba(255,255,255,.05)}td{border:none;padding:6px 0}.td-label{display:block;font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:4px}}</style></head><body><?php if (!$authorized): ?><div class="wrap"><div class="card login"><div class="logo"><img src="../assets/logo-dark.svg" alt="Unistone"></div><h1 class="title">Unistone CRM</h1><p class="sub">Вхід до закритої адмін-панелі. Доступ тільки для адміністраторів.</p><form method="post"><input name="username" placeholder="Логін" autocomplete="username" required><div style="height:12px"></div><input type="password" name="password" placeholder="Пароль" autocomplete="current-password" required><div style="height:16px"></div><button class="btn" type="submit" style="width:100%">Увійти</button><?php if ($error): ?><div class="err"><?= htmlspecialchars($error, ENT_QUOTES, 'UTF-8') ?></div><?php endif; ?></form></div></div><?php else: ?><div class="wrap"><div class="top"><div class="head-left"><div class="logo"><img src="../assets/logo-dark.svg" alt="Unistone"></div><div><div style="font-size:28px;font-weight:800">CRM заявки</div><div style="font-size:14px;color:var(--muted)">Пошук, статуси, нотатки та експорт</div></div></div><div style="display:flex;gap:10px;flex-wrap:wrap"><button class="btn ghost" onclick="exportCsv()">Експорт CSV</button><a class="btn ghost" href="?logout=1">Вийти</a></div></div><div class="grid"><div class="card metric"><div class="l">Усього</div><div class="n" id="m-all">0</div></div><div class="card metric"><div class="l">Нові</div><div class="n" id="m-new" style="color:#9fc2ff">0</div></div><div class="card metric"><div class="l">В роботі</div><div class="n" id="m-inwork" style="color:#f1d59d">0</div></div><div class="card metric"><div class="l">Закриті</div><div class="n" id="m-done" style="color:#8ff0b1">0</div></div></div><div class="card table-card"><div class="tools"><div class="tools-left"><button class="filter active" data-filter="all">Усі</button><button class="filter" data-filter="buy">Купівля</button><button class="filter" data-filter="sell">Продаж</button><button class="filter" data-status="new">Нові</button><button class="filter" data-status="inwork">В роботі</button><button class="filter" data-status="done">Закриті</button></div><div class="tools-right"><input id="search" placeholder="Пошук: ім’я, телефон, email, актив, регіон" style="min-width:290px;max-width:420px"></div></div><div style="overflow:auto"><table><thead><tr><th>Ім’я</th><th>Тип</th><th>Контакти</th><th>Актив</th><th>Бюджет / ціна</th><th>Статус</th><th>Дата</th><th></th></tr></thead><tbody id="tbody"></tbody></table></div><div class="empty" id="empty" style="display:none">Заявок поки немає або нічого не знайдено.</div></div></div><div class="modal" id="modal"><div class="card modal-card"><div style="display:flex;justify-content:space-between;gap:12px;align-items:center;margin-bottom:14px"><div style="font-size:22px;font-weight:800">Деталі заявки</div><button class="mini" onclick="closeModal()">Закрити</button></div><div class="modal-grid" id="modal-grid"></div><div style="margin-top:12px"><b style="display:block;font-size:11px;color:var(--muted);letter-spacing:.08em;text-transform:uppercase;margin-bottom:8px">Нотатка менеджера</b><textarea id="modal-note" rows="5"></textarea></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:12px"><div><b style="display:block;font-size:11px;color:var(--muted);letter-spacing:.08em;text-transform:uppercase;margin-bottom:8px">Статус</b><select id="modal-status"><option value="new">Новий</option><option value="inwork">В роботі</option><option value="done">Закрито</option><option value="rejected">Відмова</option></select></div><div></div></div><div class="modal-actions"><button class="btn ghost" onclick="deleteCurrent()">Видалити</button><button class="btn" onclick="saveCurrent()">Зберегти</button></div></div></div><script>let leads=[];let current=null;let typeFilter='all';let statusFilter='all';const tbody=document.getElementById('tbody');const empty=document.getElementById('empty');async function load(){const r=await fetch('../backend/leads.php',{cache:'no-store'});const d=await r.json();leads=d.leads||[];render()}function metrics(data){document.getElementById('m-all').textContent=data.length;document.getElementById('m-new').textContent=data.filter(x=>(x.status||'new')==='new').length;document.getElementById('m-inwork').textContent=data.filter(x=>x.status==='inwork').length;document.getElementById('m-done').textContent=data.filter(x=>x.status==='done').length;}function render(){const q=(document.getElementById('search').value||'').toLowerCase().trim();let rows=leads.filter(l=>{const typeOk=typeFilter==='all'||l.type===typeFilter;const statusOk=statusFilter==='all'||(l.status||'new')===statusFilter;const hay=[l.name,l.phone,l.email,l.asset_type,l.region,l.message,l.budget,l.price].join(' ').toLowerCase();return typeOk&&statusOk&&(!q||hay.includes(q));});metrics(leads);tbody.innerHTML=rows.map(l=>row(l)).join('');empty.style.display=rows.length?'none':'block';}function badgeStatus(s){const map={new:'Новий',inwork:'В роботі',done:'Закрито',rejected:'Відмова'};return `<span class="badge ${s||'new'}">${map[s||'new']||s}</span>`;}function row(l){const date=l.created_at?new Date(l.created_at).toLocaleString('uk-UA'):'—';const type=l.type==='buy'?'🏭 Купівля':'💼 Продаж';return `<tr><td><span class="td-label">Ім’я</span><strong>${esc(l.name||'—')}</strong></td><td><span class="td-label">Тип</span>${type}</td><td><span class="td-label">Контакти</span>${esc(l.phone||'—')}<br><span style="color:var(--muted)">${esc(l.email||'—')}</span></td><td><span class="td-label">Актив</span>${esc(l.asset_type||'—')}<br><span style="color:var(--muted)">${esc(l.region||'—')}</span></td><td><span class="td-label">Бюджет / ціна</span>${esc(l.budget||l.price||'—')}</td><td><span class="td-label">Статус</span>${badgeStatus(l.status)}</td><td><span class="td-label">Дата</span>${date}</td><td><div class="row-actions"><button class="mini" onclick="openModal('${String(l.id)}')">Відкрити</button><button class="mini" onclick="quickStatus('${String(l.id)}','inwork')">В роботу</button><button class="mini" onclick="quickStatus('${String(l.id)}','done')">Закрити</button></div></td></tr>`}function esc(v){return String(v).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}document.querySelectorAll('.filter').forEach(btn=>btn.addEventListener('click',()=>{if(btn.dataset.filter){typeFilter=btn.dataset.filter;document.querySelectorAll('[data-filter]').forEach(x=>x.classList.remove('active'));btn.classList.add('active')}if(btn.dataset.status){statusFilter=btn.dataset.status===statusFilter?'all':btn.dataset.status;document.querySelectorAll('[data-status]').forEach(x=>x.classList.remove('active'));if(statusFilter!=='all') document.querySelector(`[data-status="${statusFilter}"]`).classList.add('active');}render()}));document.getElementById('search').addEventListener('input',render);function openModal(id){current=leads.find(x=>String(x.id)===String(id));if(!current)return;document.getElementById('modal-grid').innerHTML=[['Ім’я',current.name],['Тип',current.type==='buy'?'Купівля':'Продаж'],['Телефон',current.phone],['Email',current.email||'—'],['Актив',current.asset_type||'—'],['Бюджет / ціна',current.budget||current.price||'—'],['Регіон',current.region||'—'],['Дата',current.created_at?new Date(current.created_at).toLocaleString('uk-UA'):'—'],['Коментар',current.message||'—']].map(([k,v])=>`<div class="field"><b>${k}</b><div>${esc(v)}</div></div>`).join('');document.getElementById('modal-note').value=current.note||'';document.getElementById('modal-status').value=current.status||'new';document.getElementById('modal').classList.add('open')}function closeModal(){document.getElementById('modal').classList.remove('open')}async function saveCurrent(){if(!current)return;const fd=new FormData();fd.append('id',current.id);fd.append('status',document.getElementById('modal-status').value);fd.append('note',document.getElementById('modal-note').value);const r=await fetch('../backend/update_lead.php',{method:'POST',body:fd});const d=await r.json();if(d.ok){await load();closeModal();}}async function deleteCurrent(){if(!current||!confirm('Видалити заявку?'))return;const fd=new FormData();fd.append('id',current.id);fd.append('action','delete');const r=await fetch('../backend/update_lead.php',{method:'POST',body:fd});const d=await r.json();if(d.ok){await load();closeModal();}}async function quickStatus(id,status){const fd=new FormData();fd.append('id',id);fd.append('status',status);const r=await fetch('../backend/update_lead.php',{method:'POST',body:fd});const d=await r.json();if(d.ok) await load()}function exportCsv(){window.open('../storage/leads.csv','_blank')}document.getElementById('modal').addEventListener('click',e=>{if(e.target.id==='modal')closeModal()});load();</script><?php endif; ?></body></html>